package main

import (
	"html/template"
	"log"
	"net/http"
)

type Comment struct {
	Author string
	Body   template.HTML
}

var comments = []Comment{
	{
		Author: "Alice",
		Body:   template.HTML("Hello, <b>world</b>!"),
	},
	{
		Author: "Bob",
		Body:   template.HTML("This is <i>great</i> content."),
	},
	{
		Author: "Charlie",
		Body:   template.HTML("Visit <a href=\"https://example.com\">my site</a>."),
	},
}

var pageTmpl = template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<title>User Comments</title>
</head>
<body>
	<h1>User Comments</h1>
	{{range .}}
	<div class="comment">
		<h3>{{.Author}}</h3>
		<p>{{.Body}}</p>
	</div>
	{{else}}
	<p>No comments available.</p>
	{{end}}
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := pageTmpl.Execute(w, comments); err != nil {
		http.Error(w, "failed to render template", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/", commentsHandler)
	log.Println("Server listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}